public int sumOfDigits(int[] nums) {
    int minVal = Arrays.stream(nums).min().getAsInt();
    int digitSum = 0;
    while (minVal > 0) {
        digitSum += minVal % 10;
        minVal /= 10;
    }
    return digitSum % 2 == 0 ? 1 : 0;
}
```


